#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;
int n, m, f[MAXN];
char s[MAXN];
int Find(int x)
{
	return x == f[x] ? x : f[x] = Find(f[x]);
}
void merge(int a, int b)
{
	f[Find(a)] = Find(b);
}
int main(void)
{
	cin>>n>>m; 
	for (int i = 1; i <= n; ++i)
	{
		f[i] = i;
		cin >> s[i];
	}
	for (int i = 1, a, b; i < n; ++i)
	{
		cin>>a>>b;
		if (s[a] == s[b]) merge(a, b);
	}
	for (int i = 1, a, b; i <= m; ++i)
	{
		char c;
		cin >> a >> b >> c;
		if (Find(a) == Find(b) && s[a] != c)
		{
			putchar('0');
		}
		else
		{
			putchar('1');
		}
	}
	return false;
}
